import{_ as a,o as i,c as l,ae as o}from"./chunks/framework.jfJLTIcL.js";const k=JSON.parse('{"title":"API Key 指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/api-keys.md","filePath":"zh-CN/api-keys.md","lastUpdated":1777283429000}'),t={name:"zh-CN/api-keys.md"};function d(r,e,s,n,c,h){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="api-key-指南" tabindex="-1">API Key 指南 <a class="header-anchor" href="#api-key-指南" aria-label="Permalink to &quot;API Key 指南&quot;">​</a></h1><h2 id="两类不同的-key" tabindex="-1">两类不同的 Key <a class="header-anchor" href="#两类不同的-key" aria-label="Permalink to &quot;两类不同的 Key&quot;">​</a></h2><h3 id="adminkey" tabindex="-1"><code>adminKey</code> <a class="header-anchor" href="#adminkey" aria-label="Permalink to &quot;`adminKey`&quot;">​</a></h3><p><code>adminKey</code> 只用于：</p><ul><li><code>/admin/status</code></li><li><code>/admin/providers</code></li><li><code>/admin/routing</code></li><li><code>/admin/api-keys</code></li></ul><p><code>adminKey</code> 属于宿主机管理员，不应该发给普通客户端。</p><h3 id="external-api-key" tabindex="-1">external API key <a class="header-anchor" href="#external-api-key" aria-label="Permalink to &quot;external API key&quot;">​</a></h3><p>external API key 用于：</p><ul><li><code>/v1/models</code></li><li><code>/v1/audio/transcriptions</code></li></ul><p>这是局域网客户端和内部集成的标准凭据。</p><p>无头服务端首次启动时，如果还没有 external API key，会自动创建一把名为 <code>default</code> 的初始 key。完整值会写入服务端数据目录的 <code>initial-api-key.json</code>，也可以由管理员通过 <code>vilab keys initial</code> 查询。</p><p>普通列表接口和 <code>vilab keys list</code> 只展示 preview，不长期展示所有 key 的完整值。如果忘记某个完整 key，推荐创建新 key 后替换客户端配置。</p><h2 id="推荐签发策略" tabindex="-1">推荐签发策略 <a class="header-anchor" href="#推荐签发策略" aria-label="Permalink to &quot;推荐签发策略&quot;">​</a></h2><ul><li>一把 key 对应一个项目或设备</li><li>不建议长期整团队共用一把 key</li><li>某个 key 泄露时可以独立吊销，不影响其他调用方</li><li>用量可以按集成来源而不是按个人来区分</li></ul><h2 id="创建与吊销流程" tabindex="-1">创建与吊销流程 <a class="header-anchor" href="#创建与吊销流程" aria-label="Permalink to &quot;创建与吊销流程&quot;">​</a></h2><ol><li>打开 <strong>设置 → External API keys</strong></li><li>以项目粒度创建新 key</li><li>立即复制完整值</li><li>只把它分发给对应的集成方</li><li>集成下线或泄露时直接吊销</li></ol><h2 id="命名示例" tabindex="-1">命名示例 <a class="header-anchor" href="#命名示例" aria-label="Permalink to &quot;命名示例&quot;">​</a></h2><ul><li><code>web-dashboard-prod</code></li><li><code>web-dashboard-staging</code></li><li><code>python-batch-reports</code></li><li><code>warehouse-mic-gateway-02</code></li></ul><h2 id="标准请求头" tabindex="-1">标准请求头 <a class="header-anchor" href="#标准请求头" aria-label="Permalink to &quot;标准请求头&quot;">​</a></h2><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer vilab_xxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><h2 id="当前暂不包含" tabindex="-1">当前暂不包含 <a class="header-anchor" href="#当前暂不包含" aria-label="Permalink to &quot;当前暂不包含&quot;">​</a></h2><p>这一阶段没有实现：</p><ul><li>Key scope</li><li>过期时间</li><li>单 key 限流</li><li>团队级权限控制</li></ul>',23)])])}const y=a(t,[["render",d]]);export{k as __pageData,y as default};
